2. lead_mtd_coalesce = 
var refdate = EOMONTH(MAX('ktws DIM_CALENDAR_KTWS'[Date]), 0)
var cal =
TOTALMTD(
    CALCULATE(
        SUM('ktws FCT_LEAD'[cnt]), 
        'ktws FCT_LEAD'[close_dt] > refdate || ISBLANK( 'ktws FCT_LEAD'[close_dt] ) || NOT ISBLANK( 'ktws FCT_LEAD'[last_retail_sales_dt] )),
        'ktws DIM_CALENDAR_KTWS'[Date])

return COALESCE(cal, 0)

3. cntrct_mtd_(target)_cond = 
var val = IF( ISFILTERED('ktws DIM_MNG_USER'[name]) || ISFILTERED('ktws DIM_MNG_USER'[dept_nm]) || ISFILTERED('ktws DIM_MNG_USER'[group_name]), [3. cntrct_funnel_(mtd_target)_sc], [3. cntrct_mtd_(target)_dealer])

RETURN COALESCE(val,0)

4. sales_mtd_(target)_cond = 
var val = IF( ISFILTERED('ktws DIM_MNG_USER'[name]) || ISFILTERED('ktws DIM_MNG_USER'[dept_nm]) || ISFILTERED('ktws DIM_MNG_USER'[group_name]), [4. sales_mtd_(target)_sc/coalesce], [4. sales_mtd_(target)_dealer])

RETURN COALESCE(val, 0)

